#include <bits/stdc++.h>
using namespace std;
long long n,m,a[1005],mx,num;
bool cmp(long long x,long long y)
{
	return x>y;
}
int main()
{
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		cin>>a[i];
	}
	sort(a+1,a+1+n,cmp);
	for(int i=1;i<=min(n,m);i++)
	{
		long long t=a[i]*i;
		if(t>=mx)
		{
			num=a[i];
			mx=t;
		}
	}
	cout<<num<<" "<<mx;
	return 0;
}
